### Writing Messaging Framework Instrumentation with MessageShim in Node.js

Source: https://github.com/newrelic/node-newrelic/blob/main/NEWS.md

The `MessageShim` class, accessible via the `newrelic.instrumentMessages()` API method, is introduced for writing instrumentation for messaging frameworks in Node.js. This allows New Relic to monitor message-driven applications effectively. It requires the `newrelic` module to be imported.

```javascript
const newrelic = require('newrelic');
const amqplib = require('amqplib');

async function instrumentAmqplib() {
  const connection = await amqplib.connect('amqp://localhost');
  const channel = await connection.createChannel();

  // Example of using MessageShim for amqplib instrumentation
  newrelic.instrumentMessages(channel, function(shim) {
    shim.recordProduce({ name: 'sendQueue' });
    shim.recordConsume({ name: 'receiveQueue' });
    console.log('amqplib instrumented');
  });
}

instrumentAmqplib().catch(console.error);
```

